<script setup lang="ts">
import * as z from 'zod'; import type { FormSubmitEvent } from '@nuxt/ui'
const route = useRoute(); const schema = z.object({ username: z.string().min(1), password: z.string().min(8) }); type Schema = z.output<typeof schema>; const state = reactive<Partial<Schema>>({ username: String(route.query.login_hint || ''), password: '' }); const error = ref('')
async function submit(event: FormSubmitEvent<Schema>) { try { const result = await $fetch<{ redirectTo: string }>('/api/auth/new-password', { method: 'POST', body: { ...event.data, clientId: String(route.query.client_id || 'default-client'), redirectUri: String(route.query.redirect_uri || 'http://localhost:3001/callback'), scope: String(route.query.scope || 'openid'), state: String(route.query.state || ''), nonce: String(route.query.nonce || ''), codeChallenge: String(route.query.code_challenge || '') } }); await navigateTo(result.redirectTo, { external: true }) } catch (cause: any) { error.value = cause?.data?.message || cause?.message } }
</script>
<template><AuthShell title="新しいパスワードが必要です" description="仮パスワードを恒久パスワードへ変更します"><UAlert v-if="error" color="error" variant="soft" :description="error" class="mb-5" /><UForm :schema="schema" :state="state" class="space-y-5" @submit="submit"><UFormField name="username" label="ユーザー名" required><UInput v-model="state.username" class="w-full" /></UFormField><UFormField name="password" label="新しいパスワード" required><UInput v-model="state.password" type="password" class="w-full" /></UFormField><UButton type="submit" label="パスワードを変更" block size="lg" /></UForm></AuthShell></template>
